# Azure Function to handle http requests
import logging, azure, json, hashlib

import datetime as dt


def main(req):
    # Get HTTP Headers
    req_headers = req.headers

    try:

        # Validate incoming request is in json format
        req_json = req.get_json()

        # Extract Data
        webhook_id = req_headers["x-ms-webhook-id"]
        
        webhook_type = req_headers["x-ms-webhook-type"]

        payload = req_json['data']

        body = {
            "webhookId": webhook_id,
            "requestType": webhook_type,
            "requestTimestamp": req.headers["x-ms-webhook-timestamp"],
            "requestId": hashlib.sha1(req.body).hexdigest(),
            "body" : payload
        }
    except Exception as e:

        logging.exception(e)
        
        return func_response(405,'No json provided. Please provide Json payload')


    # Create and populate new HTTP Response
    response = azure.functions_worker.HttpResponse("201")
    
    try:
        response.headers['Content-Type'] = 'application/json'

        response.body = json.dumps(body)

    except Exception as e:
        logging.exception(e)
        
        return func_response(500,'Could not serialize')
    
    return response



def func_response(status, body):
    """Return a function response object"""
    return { "body": str(body), 
        'statusCode': status }